import os
import json
import time
import sys
import requests
import datetime as dt


def _now_utc():
    return dt.datetime.utcnow().replace(tzinfo=dt.timezone.utc)


def _fmt_jql_time(ts):
    return ts.strftime('%Y/%m/%d %H:%M')


def _load_connector():
    try:
        with open('/run/connector.json', 'r', encoding='utf-8') as f:
            return json.load(f)
    except Exception:
        return {'file': 'main.py'}


def _build_session(email, api_token):
    s = requests.Session()
    s.auth = (email, api_token)
    s.headers.update({'Accept': 'application/json'})
    return s


def _parse_search_response(resp):
    if resp.status_code == 429:
        ra = resp.headers.get('Retry-After')
        return {
            'retry_after': int(ra) if ra and ra.isdigit() else 60,
            'status_code': resp.status_code,
            'file': 'main.py',
        }

    if not resp.ok:
        text = None
        try:
            text = resp.text
        except Exception:
            text = None
        return {
            'error': f'HTTP {resp.status_code}',
            'status_code': resp.status_code,
            'text': text,
            'file': 'main.py',
        }

    data = resp.json()
    issues = data.get('issues', [])
    if issues:
        issue = issues[0]
        return {'found': True, 'issueKey': issue.get('key')}

    return {'found': False, 'file': 'main.py'}


def _search_once(session, base_url, jql):
    base = base_url.rstrip('/')

    # Prefer the new GET /rest/api/3/search/jql endpoint; fallback to POST /rest/api/3/search
    try:
        url_get = base + '/rest/api/3/search/jql'
        params = {'jql': jql, 'maxResults': 1, 'fields': 'key'}
        resp = session.get(url_get, params=params, timeout=30)

        if resp.status_code in (404, 405, 410):
            url_post = base + '/rest/api/3/search'
            payload = {'jql': jql, 'maxResults': 1, 'fields': ['key']}
            resp = session.post(url_post, json=payload, timeout=30)

        return _parse_search_response(resp)

    except requests.RequestException as e:
        return {'error': str(e), 'status_code': None, 'text': None, 'file': 'main.py'}


def main():
    cfg_all = _load_connector()
    auth = cfg_all.get('auth', {})
    conf = cfg_all.get('configuration', {})

    email = auth.get('email') or os.environ.get('AUTH_EMAIL')
    api_token = auth.get('apiToken') or os.environ.get('AUTH_APITOKEN')
    base_url = conf.get('baseUrl') or os.environ.get('CONFIG_BASEURL')
    assignee_id = conf.get('assigneeAccountId') or os.environ.get('CONFIG_ASSIGNEEACCOUNTID')
    poll = int(conf.get('pollIntervalSeconds', 5) or 5)
    max_wait = int(conf.get('maxWaitSeconds', 300) or 300)
    jql_scope = (conf.get('jqlScope') or '').strip()

    start = _now_utc()
    deadline = start + dt.timedelta(seconds=max_wait)

    if not email or not api_token or not base_url or not assignee_id:
        out = {
            'status': 'error',
            'message': 'Missing required configuration/auth: email, apiToken, baseUrl, assigneeAccountId must be provided',
        }
        print(json.dumps(out))
        return

    session = _build_session(email, api_token)

    base_clause = f"assignee CHANGED TO accountId({assignee_id}) AFTER '{_fmt_jql_time(start)}'"
    jql = f"({jql_scope}) AND {base_clause}" if jql_scope else base_clause

    while True:
        now = _now_utc()

        if now >= deadline:
            out = {
                'status': 'timeout',
                'found': False,
                'message': f'No assignment to target user detected within {max_wait} seconds',
                'assigneeAccountId': assignee_id,
                'jqlUsed': jql,
                'startedAtUtc': start.isoformat().replace('+00:00', 'Z'),
                'endedAtUtc': now.isoformat().replace('+00:00', 'Z'),
                'durationSeconds': int((now - start).total_seconds()),
            }
            print(json.dumps(out))
            return

        try:
            res = _search_once(session, base_url, jql)
        except Exception as e:
            out = {'status': 'error', 'message': str(e)}
            print(json.dumps(out))
            return

        if 'retry_after' in res:
            sleep_s = max(res.get('retry_after', poll), poll)
            time.sleep(min(sleep_s, max_wait))
            continue

        if 'error' in res:
            out = {
                'status': 'error',
                'message': res.get('error'),
                'httpStatus': res.get('status_code'),
                'details': res.get('text'),
                'jqlUsed': jql,
                'file': 'main.py',
            }
            print(json.dumps(out))
            return

        if res.get('found'):
            key = res.get('issueKey')
            out = {
                'status': 'success',
                'found': True,
                'assigneeAccountId': assignee_id,
                'matchedIssueKey': key,
                'matchedIssueUrl': base_url.rstrip('/') + '/browse/' + key,
                'jqlUsed': jql,
                'startedAtUtc': start.isoformat().replace('+00:00', 'Z'),
                'endedAtUtc': now.isoformat().replace('+00:00', 'Z'),
                'durationSeconds': int((now - start).total_seconds()),
            }
            print(json.dumps(out))
            return

        time.sleep(poll)


if __name__ == '__main__':
    main()
